3	const PATH_CAPTURE_START = "__T3CODE_PATH_START__";
4	const PATH_CAPTURE_END = "__T3CODE_PATH_END__";
5	const PATH_CAPTURE_COMMAND = [
6	  `printf '%s\n' '${PATH_CAPTURE_START}'`,
7	  "printenv PATH",
8	  `printf '%s\n' '${PATH_CAPTURE_END}'`,
9	].join("; ");
