### 5. EXISTING HOOKS PATTERNS

**Location**: `/apps/web/src/hooks/`

**1. `useTheme.ts`** - Theme management
```typescript
export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme; // "light" | "dark" | "system"

  const resolvedTheme: "light" | "dark" = 
    theme === "system" ? (snapshot.systemDark ? "dark" : "light") : theme;

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  return { theme, setTheme, resolvedTheme } as const;
}
```
- Uses external store pattern with listeners
- Listens to system preference changes (media query)
- Listens to storage changes from other tabs
- Applies class to `document.documentElement`
- Suppresses transitions during theme change

**2. `useMediaQuery.ts`** - Media query hook
```typescript
export function useMediaQuery(query: string): boolean {
  const [matches, setMatches] = useState(() => getMediaQueryMatch(query));

  useEffect(() => {
    const mediaQueryList = window.matchMedia(query);
    const handleChange = () => setMatches(mediaQueryList.matches);

    mediaQueryList.addEventListener("change", handleChange);
    return () => mediaQueryList.removeEventListener("change", handleChange);
  }, [query]);

  return matches;
}
```

**3. `useTurnDiffSummaries.ts`** - Memoized diff summaries
```typescript
export function useTurnDiffSummaries(activeThread: Thread | undefined) {
  const turnDiffSummaries = useMemo(() => {
    if (!activeThread) return [];
    return activeThread.turnDiffSummaries;
  }, [activeThread]);

  const inferredCheckpointTurnCountByTurnId = useMemo(
    () => inferCheckpointTurnCountByTurnId(turnDiffSummaries),
    [turnDiffSummaries],
  );

  return { turnDiffSummaries, inferredCheckpointTurnCountByTurnId };
}
```

