  background: string;
  foreground: string;
  accent: string;
  sidebar: string;
  editor: string;
  terminal: string;
  statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly variant: "light" | "dark";   // controls .dark class
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

const BUILT_IN_THEMES: readonly Theme[] = [
  {
    id: "t3-dark",
    name: "T3 Dark",
    variant: "dark",
    colors: {
      background: "#0d0d12",
      foreground: "#f0f0f5",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#0a0a0f",
      editor: "#0d0d12",
      terminal: "#0a0a0f",
      statusBar: "#0a0a0f",
    },
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-light",
    name: "T3 Light",
    variant: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1c28",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f4f4f9",
      editor: "#ffffff",
      terminal: "#f8f8fd",
      statusBar: "#f0f0f8",
    },
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    variant: "dark",
    colors: {
      background: "#05050a",
      foreground: "#c0c8e0",
      accent: "oklch(0.65 0.22 250)",
      sidebar: "#030308",
      editor: "#05050a",
      terminal: "#030308",
      statusBar: "#08080f",
    },
    fontFamily: '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif',
    fontSize: 14,
  },
];

export function getTheme(id: string): Theme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? BUILT_IN_THEMES[0]!;
}

export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}
