### 4. `apps/web/src/hooks/useTheme.ts`  ← primary logic change

**Rename** the current `useTheme()` export to `useAppearanceMode()` (all internals stay). Then **add** the new color-theme system below it, following the same `useSyncExternalStore` external-store pattern.

New additions in this file:

```ts
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";
const DEFAULT_THEME_ID = "t3-dark";

// --- color-theme external store ---
let colorThemeListeners: Array<() => void> = [];
let lastColorThemeSnapshot: Theme | null = null;

function emitColorThemeChange() { ... }

function getStoredThemeId(): string {
  return localStorage.getItem(COLOR_THEME_STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

function getColorThemeSnapshot(): Theme {
  const theme = getTheme(getStoredThemeId());
  if (lastColorThemeSnapshot?.id === theme.id) return lastColorThemeSnapshot;
  lastColorThemeSnapshot = theme;
  return theme;
}

function applyColorTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) document.documentElement.classList.add("no-transitions");

  const root = document.documentElement;
  // Core palette — overrides :root / .dark stylesheet declarations
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.background);
  root.style.setProperty("--card-foreground", theme.colors.foreground);
  root.style.setProperty("--popover", theme.colors.background);
  root.style.setProperty("--popover-foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);
  // Component-specific variables (consumed by sidebar/editor/terminal when they opt in)
  root.style.setProperty("--t3-sidebar", theme.colors.sidebar);
  root.style.setProperty("--t3-editor", theme.colors.editor);
  root.style.setProperty("--t3-terminal", theme.colors.terminal);
  root.style.setProperty("--t3-status-bar", theme.colors.statusBar);
  // Font
  root.style.setProperty("--t3-font-family", theme.fontFamily);
  root.style.setProperty("--t3-font-size", `${theme.fontSize}px`);
  // Sync .dark class so border/muted/scrollbar palette matches
  root.classList.toggle("dark", theme.variant === "dark");

  if (suppressTransitions) {
    root.offsetHeight; // force reflow
    requestAnimationFrame(() => root.classList.remove("no-transitions"));
  }
}

// Apply immediately on module load
applyColorTheme(getTheme(getStoredThemeId()));

function subscribeColorTheme(listener: () => void): () => void {
  colorThemeListeners.push(listener);
  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_THEME_STORAGE_KEY) {
      applyColorTheme(getTheme(getStoredThemeId()), true);
      emitColorThemeChange();
    }
  };
  window.addEventListener("storage", handleStorage);
  return () => {
    colorThemeListeners = colorThemeListeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const theme = useSyncExternalStore(subscribeColorTheme, getColorThemeSnapshot);

  const setTheme = useCallback((id: string) => {
    localStorage.setItem(COLOR_THEME_STORAGE_KEY, id);
    applyColorTheme(getTheme(id), true);
    emitColorThemeChange();
  }, []);

  return { theme, setTheme, availableThemes: listThemes() } as const;
}
```

Keep the `useAppearanceMode()` function (renamed from `useTheme`) intact — its `applyTheme` function (which toggles `.dark`) will now be a no-op for visual state since `applyColorTheme` also manages `.dark`. The appearance mode toggle can remain available but the color theme wins when set.

