import { useTheme } from "../hooks/useTheme";
import type { Theme } from "@t3tools/shared/themes";

function ThemeSwatch({ theme }: { theme: Theme }) {
  return (
    <div
      className="relative h-14 w-full overflow-hidden rounded-md border border-border"
      style={{ background: theme.colors.background }}
      aria-hidden="true"
    >
      {/* Sidebar strip */}
      <div
        className="absolute inset-y-0 left-0 w-4"
        style={{ background: theme.colors.sidebar }}
      />
      {/* Editor area */}
      <div
        className="absolute inset-y-0 right-0"
        style={{ left: "1rem", background: theme.colors.editor }}
      />
      {/* Status bar */}
      <div
        className="absolute inset-x-0 bottom-0 h-2"
        style={{ background: theme.colors.statusBar }}
      />
      {/* Accent dot */}
      <div
        className="absolute right-2 top-2 h-2.5 w-2.5 rounded-full"
        style={{ background: theme.colors.accent }}
      />
    </div>
  );
}

export function ThemeSelector() {
  const { theme: currentTheme, setTheme, availableThemes } = useTheme();

  return (
    <div
      className="grid grid-cols-3 gap-3"
      role="radiogroup"
      aria-label="Color theme"
    >
      {availableThemes.map((t) => {
        const selected = t.id === currentTheme.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={`flex flex-col gap-2 rounded-xl border p-2 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring ${
              selected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent"
            }`}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatch theme={t} />
            <div className="flex items-center justify-between gap-1 px-0.5">
              <span
                className={`text-xs font-medium ${
                  selected ? "text-foreground" : "text-muted-foreground"
                }`}
              >
                {t.name}
              </span>
              {selected ? (
                <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

